<?php declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';$admin=vp3_require_admin_permission('customers.view');$id=(int)vp3_input('id');if(vp3_method()==='POST'){vp3_require_admin_permission('customers.manage');vp3_verify_csrf();$status=vp3_input('status');if(in_array($status,['active','suspended','closed'],true))vp3_db()->prepare('UPDATE customers SET status=?,updated_at=NOW() WHERE id=?')->execute([$status,$id]);vp3_audit('admin',(int)$admin['id'],'customer.status_updated','customer',(string)$id,['status'=>$status]);vp3_redirect('admin/customer.php?id='.$id);} $s=vp3_db()->prepare('SELECT * FROM customers WHERE id=?');$s->execute([$id]);$row=$s->fetch();if(!is_array($row)){http_response_code(404);exit('Customer not found.');}$pageTitle='Customer';require VP3_ROOT.'/includes/admin-header.php';?><h1><?=vp3_e($row['name'])?></h1><div class="grid two"><article class="card"><h3>Customer details</h3><p><?=vp3_e($row['company_name'])?><br><?=vp3_e($row['email'])?><br><?=vp3_e($row['phone'])?></p><form method="post"><?=vp3_csrf_field()?><div class="field"><label>Status</label><select name="status"><?php foreach(['active','suspended','closed'] as $st):?><option <?=$row['status']===$st?'selected':''?>><?=vp3_e($st)?></option><?php endforeach;?></select></div><button class="button small">Update</button></form></article><article class="card"><h3>Account relationships</h3><p>UUID: <?=vp3_e($row['customer_uuid'])?></p><p><a href="orders.php?customer_id=<?=$id?>">Orders</a> · <a href="licenses.php?customer_id=<?=$id?>">Licenses</a> · <a href="hosting.php?customer_id=<?=$id?>">Hosting</a></p></article></div><?php require VP3_ROOT.'/includes/admin-footer.php';?>